import os
import numpy as np
import cv2
from flask import Flask, request, jsonify
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
import pickle
import face_recognition
import json

app = Flask(__name__)

# Global variables
model = None
label_encoder = None
known_faces = []
known_names = []

def load_training_data(data_dir):
    """Load training data from directory"""
    global known_faces, known_names
    
    known_faces = []
    known_names = []
    
    for person_name in os.listdir(data_dir):
        person_dir = os.path.join(data_dir, person_name)
        if not os.path.isdir(person_dir):
            continue
            
        for filename in os.listdir(person_dir):
            if filename.lower().endswith(('.png', '.jpg', '.jpeg')):
                image_path = os.path.join(person_dir, filename)
                image = face_recognition.load_image_file(image_path)
                face_locations = face_recognition.face_locations(image)
                
                if len(face_locations) > 0:
                    face_encoding = face_recognition.face_encodings(image, face_locations)[0]
                    known_faces.append(face_encoding)
                    known_names.append(person_name)

def train_model():
    """Train the facial recognition model"""
    global model, label_encoder
    
    if len(known_faces) == 0:
        raise ValueError("No training data available")
    
    # Encode labels
    label_encoder = LabelEncoder()
    encoded_names = label_encoder.fit_transform(known_names)
    
    # Train SVM model
    model = SVC(kernel='linear', probability=True)
    model.fit(known_faces, encoded_names)

def initialize_system():
    """Initialize the system with training data"""
    try:
        load_training_data('employee_photos')
        train_model()
        print("System initialized successfully")
    except Exception as e:
        print(f"Error initializing system: {e}")

@app.route('/recognize', methods=['POST'])
def recognize_face():
    """API endpoint to recognize face and return confidence scores"""
    try:
        if 'image' not in request.files:
            return jsonify({'error': 'No image provided'}), 400
        
        image_file = request.files['image']
        image = face_recognition.load_image_file(image_file)
        face_locations = face_recognition.face_locations(image)
        
        if len(face_locations) == 0:
            return jsonify({'error': 'No faces detected'}), 400
        
        # Get face encodings
        face_encodings = face_recognition.face_encodings(image, face_locations)
        
        results = []
        for face_encoding in face_encodings:
            # Predict
            predictions = model.predict_proba([face_encoding])[0]
            predicted_class = model.predict([face_encoding])[0]
            
            # Get class names
            class_names = label_encoder.classes_
            
            # Create probability distribution
            prob_distribution = {}
            for i, class_name in enumerate(class_names):
                prob_distribution[class_name] = float(predictions[i])
            
            results.append({
                'confidence_scores': prob_distribution,
                'predicted_class': class_name,
                'max_confidence': float(np.max(predictions))
            })
        
        return jsonify({'results': results})
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/status', methods=['GET'])
def get_status():
    """Get system status"""
    try:
        return jsonify({
            'status': 'ready',
            'model_trained': model is not None,
            'known_faces_count': len(known_faces),
            'known_persons': list(label_encoder.classes_) if label_encoder else []
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    initialize_system()
    app.run(host='0.0.0.0', port=5000, debug=False)